BLACK = (0, 0, 0)
BLUE = (0, 0, 255)
GREEN = (0, 255, 0)

# Initialize Pygame
pygame.init()

# Set up the display
screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
pygame.display.set_caption('MultiAgentMaze')

clock = pygame.time.Clock()


class Player:
    def __init__(self, x, y, color):
        self.x = x
        self.y = y
        self.color = color

    def move(self, dx, dy):
        self.x += dx
        self.y += dy

    def draw(self, surface):
        pygame.draw.rect(surface, self.color, (self.x * BLOCK_SIZE, self.y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))


class MultiAgentMaze:
    def __init__(self, maze_layout, players):
        self.maze_layout = maze_layout
        self.players = players

    def draw_maze(self, surface):
        for y, row in enumerate(self.maze_layout):
            for x, cell in enumerate(row):
                if cell == 1:
                    pygame.draw.rect(surface, BLACK, (x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                elif cell == 2:
                    pygame.draw.rect(surface, GREEN, (x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))

    def draw(self, surface):
        self.draw_maze(surface)
        for player in self.players:
            player.draw(surface)

    def handle_events(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit()
                sys.exit()
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    self.players[0].move(-1, 0)
                elif event.key == pygame.K_RIGHT:
                    self.players[0].move(1, 0)
                elif event.key == pygame.K_UP:
                    self.players[0].move(0, -1)
                elif event.key == pygame.K_DOWN:
                    self.players[0].move(0, 1)

    def run(self):
        while True:
            self.handle_events()
            screen.fill(WHITE)
            self.draw(screen)
            pygame.display.flip()
            clock.tick(60)


